import Foundation
import Combine

class User {
    private var cancellables = Set<AnyCancellable>()

    @available(*, deprecated, message: "Use DIService.resolve()")
    public static let current = User()

    var pendingSaveJob: Job?
    var pendingSearchId: String?
    var pendingScreen: Screen?
    var pendingSourcePage: SourcePage?
    var pendingTrackingProperties: SaveSearchTrackingProperties?
    var pendingSaveSearch: Search?

    // This is a special case, User is also used in DIRegistry
    // LazyInjected used to prevent pointers loops
    // TODO: remove static instance, add constructor, remove that scheise 
    @LazyInjected private var userService: UserService
    @LazyInjected private var firebaseManager: FirebaseManager

    @LazyInjected private var savedJobsRepository: SavedJobsRepository
    @LazyInjected private var jobApplicationsRepository: JobApplicationsRepository

    @LazyInjected private var recentSearchRepository: RecentSearchesRepository
    @LazyInjected private var savedSearchesRepository: SavedSearchesRepository

    @LazyInjected private var firebaseTracker: FirebaseTracker
    @LazyInjected private var branchTracker: BranchTracker

    @LazyInjected private var resolveCountry: ResolveCountryUseCase
    @LazyInjected private var getDeviceId: GetDeviceIdUseCase

    func loadRepositories() {
        guard isLoggedIn else { return }

        Runner.async(.userLoadRepositories) { [self] in
            try? await savedJobsRepository.loadSavedJobs()
            try? await jobApplicationsRepository.load()
            await savedSearchesRepository.loadSavedSearches()
        }
    }

    func resetRepositories() {
        Runner.async(.userResetRepositories) { [self] in
            await savedJobsRepository.reset()
            await jobApplicationsRepository.reset()
            await savedSearchesRepository.reset()
        }
    }

    enum UserDefaultsKey: String, CaseIterable {
        case hasLaunched
        case sessionCount
        case hasCheckedGDPR
        case hasCheckedIPCountry
        case recentSearches
        case credentials
        case freshJobsNotificationsEnabled
        case notificationsEnabled
        case matchNotificationsEnabled
        case searchCount
        case matchesCount
        case appReviewDialogShownCount
        case saveJobsCoachShown
        case quickApplyCoachShown
        case hasResume
        case lastTimeNpsSurveyShown
        case altOnboardingSelectedCountry
        case defaultCountry = "AppDefaultCountry" // legacy
        case oneClickApplyCoachShown // legacy, delete in a couple of years
        case remoteConfigMockedValues
        case onboardingUserChoices

        // Why it is called this way?
        var stateDefaultsKey: String {
            return self.rawValue
        }
    }

    var userId: String? {
        return credentials?.userId
    }

    var userTrackingId: String {
        return credentials?.userId ?? getDeviceId()
    }

    var userIdOrAnonymous: String {
        return credentials?.userId ?? "anonymous" // used for some API V3 calls
    }

    let emailAddressSubject = CurrentValueSubject<String?, Never>(nil)
    var emailAddress: String? {
        emailAddressSubject.value
    }

    var credentials: OAuth? {
        get {
            return OAuth.from(data: UserDefaults.standard.data(forKey: UserDefaultsKey.credentials.stateDefaultsKey))
        }

        set(newValue) {
            if let newValue,
                let data = newValue.toData {
                UserDefaults.standard.set(data, forKey: UserDefaultsKey.credentials.stateDefaultsKey)
            } else {
                UserDefaults.standard.removeObject(forKey: UserDefaultsKey.credentials.stateDefaultsKey)
            }

            updateLoggedInStatus()
        }
    }

    var selectedCountry: Country {
        get {
            return resolveCountry()
        }

        set (newValue) {
            UserDefaults.standard.set(newValue.code, forKey: UserDefaultsKey.defaultCountry.stateDefaultsKey)
        }
    }

    @UserDefaultsBoolValue(key: .freshJobsNotificationsEnabled)
    var freshJobsNotificationsEnabled: Bool

    @UserDefaultsBoolValue(key: .notificationsEnabled)
    var notificationsEnabled: Bool

    @UserDefaultsBoolValue(key: .matchNotificationsEnabled)
    var matchNotificationsEnabled: Bool

    @UserDefaultsIntValue(key: .searchCount)
    var searchCount: Int

    @UserDefaultsIntValue(key: .matchesCount)
    var matchesCount: Int

    @UserDefaultsBoolValue(key: .hasLaunched)
    var hasLaunched: Bool

    @UserDefaultsIntValue(key: .sessionCount)
    var sessionCount: Int

    @UserDefaultsBoolValue(key: .hasCheckedIPCountry)
    var hasCheckedIPCountry: Bool

    @UserDefaultsBoolValue(key: .hasCheckedGDPR)
    var hasCheckedGDPR: Bool

    @UserDefaultsIntValue(key: .appReviewDialogShownCount)
    var appReviewDialogShownCount: Int

    @UserDefaultsBoolValue(key: .saveJobsCoachShown)
    var saveJobsCoachShown: Bool

    @UserDefaultsBoolValue(key: .quickApplyCoachShown)
    var quickApplyCoachShown: Bool

    func logout() {
        if !isLoggedIn { return }
        credentials = nil
        emailAddressSubject.send(nil)

        let event = UserEvents.signOutSuccessful()
        firebaseTracker.track(event)
        branchTracker.track(event)

        resetRepositories()
    }

    lazy var loggedIn: CurrentValueSubject<Bool, Never> = {
        CurrentValueSubject<Bool, Never>(isLoggedIn)
    }()

    var isLoggedIn: Bool {
        return credentials?.accessToken != nil && credentials?.userId != nil
    }

    func updateLoggedInStatus() {
        loggedIn.send(isLoggedIn)
    }

    func updateSearchCount() {
        if searchCount < Int.max {
            searchCount += 1
        }
    }

    func updateMatchesCount() {
        if matchesCount < Int.max {
            matchesCount += 1
        }
    }

    func shouldShowAppReviewDialog(
        analyticaSessionManager: AnalyticaSessionManager = DIService.resolve()
    ) -> Bool {
        if appReviewDialogShownCount >= 2 { return false }

        let appFeedbackQualification = firebaseManager.remoteConfigValue(for: .appFeedbackQualification).boolValue
        let appFeedbackSessionThreshold = firebaseManager.remoteConfigValue(for: .appFeedbackSessionThreshold).numberValue.intValue
        let currentSessionCount = analyticaSessionManager.session.sessionCount

        if appFeedbackQualification && currentSessionCount >= appFeedbackSessionThreshold {
            appReviewDialogShownCount += 1
            return true
        }
        return false
    }

    func updateCredentials(_ auth: OAuth) {
        credentials = auth

        // save any pending jobs
        if let pendingSaveJob,
            let pendingScreen {
            saveJob(pendingSaveJob, searchId: pendingSearchId, screen: pendingScreen)
        }

        // save any pending searches
        if let pendingSaveSearch,
           let pendingSourcePage,
           let pendingScreen {
            saveSearch(pendingSaveSearch, sourcePage: pendingSourcePage, screen: pendingScreen, trackingProperties: pendingTrackingProperties)
        }

        pendingSaveJob = nil
        pendingSearchId = nil
        pendingSourcePage = nil
        pendingScreen = nil
        pendingSaveSearch = nil

        loadUserRelatedData()
    }

    func revokeCredentials() {
        logout()
    }

    func loadUserRelatedData() {
        fetchUserEmail()
        loadRepositories()
    }

    private func fetchUserEmail() {
        guard isLoggedIn else {
            return
        }

        Runner.async(.userFetchUserEmail) { [self] in
            do {
                let userProfile = try await userService.getUserProfile(userId: userTrackingId, siteId: selectedCountry.siteId)

                self.emailAddressSubject.send(userProfile.email)
            } catch {
                self.emailAddressSubject.send(nil)
            }
        }
    }
}

// SavedJobsRepository
extension User {
    func saveJob(_ job: Job, searchId: String?, screen: Screen) {
        guard isLoggedIn else {
            // Do we need those? They will be nullified after this method exits
            pendingSaveJob = job // save job so we can re-save after login
            pendingSearchId = searchId
            pendingScreen = screen
            return
        }

        savedJobsRepository.saveJob(userId: userTrackingId, job: job, searchId: searchId, screen: screen)
    }

    func deleteJob(_ job: Job, searchId: String?, screen: Screen) {
        savedJobsRepository.unsaveJob(userId: userTrackingId, job: job, searchId: searchId)
    }

    func isJobSaved(job: Job) async -> Bool {
        return await savedJobsRepository.isSaved(job: job)
    }
}

// SavedSearchesRepository
extension User {
    func saveSearch(_ search: Search, sourcePage: SourcePage, screen: Screen, trackingProperties: SaveSearchTrackingProperties? = nil) {
        guard isLoggedIn else {
            pendingSaveSearch = search // save jobId so we can re-save after login
            pendingSourcePage = sourcePage
            pendingScreen = screen
            pendingTrackingProperties = trackingProperties
            return
        }

        savedSearchesRepository.saveSearch(search: search, sourcePage: sourcePage, screen: screen, trackingProperties: trackingProperties)
    }
}

protocol WithUser {
    var user: User { get }
}

extension WithUser {
    var selectedCountry: Country {
        user.selectedCountry
    }
}

protocol ResolveCountryUseCase {
    func callAsFunction() -> Country
}

struct DefaultResolveCountryUseCase: ResolveCountryUseCase {
    private let countryManager: CountryManagerInstance

    init(countryManager: CountryManagerInstance = DIService.resolve()) {
        self.countryManager = countryManager
    }

    func callAsFunction() -> Country {
        let key = User.UserDefaultsKey.defaultCountry.stateDefaultsKey
        if let savedCode = UserDefaults.standard.string(forKey: key),
           let resolvedCountry = countryManager.countryForCode(savedCode) {
            return resolvedCountry
        }

        return countryManager.defaultCountry
    }
}

