import Foundation
import Testing

@testable import Jora

struct UserTests {
    let resolveCountry = MockResolveCountryUseCase()

    lazy var sut = User(resolveCountry: resolveCountry)

    @Test("User should not be logged in after logout")
    func loggedOut_isNotLoggedIn() {
        sut.credentials = OAuth(
            refreshToken: "refresh",
            accessToken: "access",
            tokenType: "bearer",
            expiresIn: 3600,
            newUser: false,
            createdAt: Date.now.timeIntervalSince1970,
            userId: "123"
        )

        sut.logout()

        #expect(sut.isLoggedIn == false)
    }

    @Test("User can be instantiated with explicit dependency")
    func canInstantiateWithExplicitDependency() {
        let customResolveCountry = MockResolveCountryUseCase()
        customResolveCountry.stubbedCountry = Countries.India

        let user = User(resolveCountry: customResolveCountry)

        #expect(user.selectedCountry.code == "IN")
    }

    @Test("User can be instantiated with default dependency")
    func canInstantiateWithDefaultDependency() {
        let user = User()

        // Should not crash and have a default country
        #expect(user.selectedCountry.code.isEmpty == false)
    }

    @Test("selectedCountry uses injected ResolveCountryUseCase")
    func selectedCountryUsesInjectedUseCase() {
        resolveCountry.stubbedCountry = Countries.Singapore

        let result = sut.selectedCountry

        #expect(result.code == "SG")
    }
}

